#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF INT_MAX
#define MIN(a, b) ((a) < (b) ? (a) : (b))
typedef struct Edge {
    int source;
    int target;
    int time;
} Edge;

int compare(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return e1->source - e2->source;
}

int calculateNetworkDelayTime(Edge *travelTimes, int travelTimesSize, int totalNodes, int startNode) {
    int *dist = (int *)calloc(totalNodes + 1, sizeof(int));
    for (int i = 1; i <= totalNodes; i++) {
        dist[i] = INF;
    }
    dist[startNode] = 0;
    int *visited = (int *)calloc(totalNodes + 1, sizeof(int));
    while (1) {
        int u = -1;
        for (int i = 1; i <= totalNodes; i++) {
            if (!visited[i] && (u == -1 || dist[i] < dist[u])) {
                u = i;
            }
        }
        if (u == -1) break;
        visited[u] = 1;
        for (int i = 0; i < travelTimesSize; i++) {
            if (travelTimes[i].source == u && !visited[travelTimes[i].target]) {
                dist[travelTimes[i].target] = MIN(dist[travelTimes[i].target], dist[u] + travelTimes[i].time);
            }
        }
    }
    int maxDist = 0;
    for (int i = 1; i <= totalNodes; i++) {
        if (dist[i] == INF) return -1;
        maxDist = (maxDist > dist[i]) ? maxDist : dist[i];
    }
    free(dist);
    free(visited);
    return maxDist;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int travelTimesSize;
        scanf("%d", &travelTimesSize);
        Edge *travelTimes = (Edge *)malloc(travelTimesSize * sizeof(Edge));
        for (int i = 0; i < travelTimesSize; i++) {
            scanf("%d %d %d", &travelTimes[i].source, &travelTimes[i].target, &travelTimes[i].time);
        }
        int totalNodes;
        scanf("%d", &totalNodes);
        int startNode;
        scanf("%d", &startNode);
        printf("%d\n", calculateNetworkDelayTime(travelTimes, travelTimesSize, totalNodes, startNode));
        free(travelTimes);
    }
    return 0;
}

