#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;

struct Edge {
    int source;
    int target;
    int time;
};

struct Compare {
    bool operator()(const pair<int, int> &a, const pair<int, int> &b) {
        return a.first > b.first;
    }
};

int calculateNetworkDelayTime(vector<vector<int>> &travelTimes, int totalNodes, int startNode) {
    vector<int> dist(totalNodes + 1, INT_MAX);
    dist[startNode] = 0;
    priority_queue<pair<int, int>, vector<pair<int, int>>, Compare> pq;
    pq.push({0, startNode});
    while (!pq.empty()) {
        int time = pq.top().first;
        int node = pq.top().second;
        pq.pop();
        if (time > dist[node]) continue;
        for (auto &e : travelTimes) {
            if (e[0] == node) {
                if (dist[e[1]] > time + e[2]) {
                    dist[e[1]] = time + e[2];
                    pq.push({dist[e[1]], e[1]});
                }
            }
        }
    }
    int maxDist = 0;
    for (int i = 1; i <= totalNodes; i++) {
        if (dist[i] == INT_MAX) return -1;
        maxDist = max(maxDist, dist[i]);
    }
    return maxDist;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int n;
        cin >> n;
        vector<vector<int>> travelTimes(n, vector<int>(3));
        for (int i = 0; i < n; i++) {
            cin >> travelTimes[i][0] >> travelTimes[i][1] >> travelTimes[i][2];
        }
        int totalNodes;
        cin >> totalNodes;
        int startNode;
        cin >> startNode;
