    public static int calculateNetworkDelayTime(int[][] travelTimes, int totalNodes, int startNode) {
        int[] dist = new int[totalNodes + 1];
        for (int i = 1; i <= totalNodes; i++) {
            dist[i] = Integer.MAX_VALUE;
        }
        dist[startNode] = 0;
        java.util.PriorityQueue<int[]> pq = new java.util.PriorityQueue<>((a, b) -> a[0] - b[0]);
        pq.offer(new int[] {0, startNode});
        while (!pq.isEmpty()) {
            int[] cur = pq.poll();
            int time = cur[0];
            int node = cur[1];
            if (time > dist[node]) continue;
            for (int[] e : travelTimes) {
                if (e[0] == node) {
                    if (dist[e[1]] > time + e[2]) {
                        dist[e[1]] = time + e[2];
                        pq.offer(new int[] {dist[e[1]], e[1]});
                    }
                }
            }
        }
        int maxDist = 0;
        for (int i = 1; i <= totalNodes; i++) {
            if (dist[i] == Integer.MAX_VALUE) return -1;
            maxDist = Math.max(maxDist, dist[i]);
        }
        return maxDist;
    }
