function calculateNetworkDelayTime(travelTimes, totalNodes, startNode) {
    const dist = new Array(totalNodes + 1).fill(Infinity);
    dist[startNode] = 0;
    const pq = [];
    pq.push([0, startNode]);
    while (pq.length > 0) {
        pq.sort((a, b) => a[0] - b[0]);
        const [time, node] = pq.shift();
        if (time > dist[node]) continue;
        for (const [u, v, t] of travelTimes) {
            if (u === node) {
                if (dist[v] > time + t) {
                    dist[v] = time + t;
                    pq.push([dist[v], v]);
                }
            }
        }
    }
    let maxDist = 0;
    for (let i = 1; i <= totalNodes; i++) {
        if (dist[i] === Infinity) return -1;
        maxDist = Math.max(maxDist, dist[i]);
    }
    return maxDist;
}

